import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

import Header from './components/Header';
import Home from './components/Home';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import GestionOfertas from './components/GestionOfertas';

function App() {
  // Cambio clave: inicializamos directamente con el valor de localStorage
  const [isLoggedIn, setIsLoggedIn] = useState(!!localStorage.getItem('token-falso'));
  const [userRole, setUserRole] = useState(localStorage.getItem('user-role')); 

  useEffect(() => {
    const role = localStorage.getItem('user-role');
    const token = localStorage.getItem('token-falso');
    if (token && role) {
      setIsLoggedIn(true);
      setUserRole(role);
    }
  }, []);

  const cerrarSesion = () => {
    localStorage.clear(); // Limpia todo de una vez
    setIsLoggedIn(false);
    setUserRole(null);
    window.location.href = '/login';
  };

  return (
    <Router>
      <Header 
        isLoggedIn={isLoggedIn} 
        userRole={userRole} 
        cerrarSesion={cerrarSesion} 
      />
      <main style={{ minHeight: 'calc(100vh - 75px)' }}>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login setIsLoggedIn={setIsLoggedIn} setUserRole={setUserRole} />} />

          <Route 
            path="/dashboard" 
            element={isLoggedIn && userRole === 'vendedor' ? <Dashboard /> : <Navigate to="/login" />} 
          />

          <Route 
            path="/ofertas/:id" 
            element={isLoggedIn && userRole === 'vendedor' ? <GestionOfertas /> : <Navigate to="/login" />} 
          />

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </main>
    </Router>
  );
}

export default App;
